List <string> GetListInputOfControlsNotAllowNull()
{
    List<string> ListInputOfControlsNotAllowNull = new List<string>();

    enControls ControlName = enControls.None;

    for (short i = 0; i < ListOfColunmData.Count; i++)
    {
        Enum.TryParse(ListOfColunmData[i].ControlName, out ControlName);

        if (ListOfColunmData[i].Generate && !ListOfColunmData[i].IsNullable && (ControlName == enControls.TextBox || ControlName == enControls.MaskedTextBox || ControlName == enControls.ComboBox))
        {
            ListInputOfControlsNotAllowNull.Add($"!string.IsNullOrWhiteSpace({RuntimeTextTemplateUiLayerDesigner.GetControlName(ControlName, ListOfColunmData[i].NameWithout_)}.Text)");
        }
    }

    return ListInputOfControlsNotAllowNull;
}

